// Day-one gate: inert until explicitly enabled after Gate 1. Also require a shared secret.
if ($env.INGEST_ENABLED !== '1') throw new Error('ingest disabled (INGEST_ENABLED != 1) — gated on legal Gate 1');
const got = $input.first().json.headers?.['x-ingest-secret'];
if (!got || got !== $env.INGEST_SECRET) throw new Error('bad ingest secret');
const b = $input.first().json.body ?? {};
const title = `Lead: ${(b.subject ?? 'untitled').toString().slice(0, 120)} (${b.source ?? 'web'})`;
return [{ json: { title } }];
